content.query:
let usd_per_token_input = 1.0/1000000.0;
let usd_per_token_output = 5.0/1000000.0;
let usd_per_token_cache_read = 0.1/1000000.0;
let usd_to_eur = 0.92;
let from_traces = traces
  | where timestamp {TimeRange}
  | where customDimensions["event"] == "tcp.ask.metrics"
  | extend in_t = todouble(customDimensions["metric_input_tokens"]),
           out_t = todouble(customDimensions["metric_output_tokens"]),
           cr_t = todouble(customDimensions["metric_cache_read_tokens"])
  | project timestamp, in_t, out_t, cr_t;
let from_metrics = customMetrics
  | where timestamp {TimeRange}
  | where name in ("tcp.ask.input_tokens", "tcp.ask.output_tokens", "tcp.ask.cache_read_tokens")
  | summarize value = sum(value) by name, timestamp
  | evaluate pivot(name, sum(value), timestamp)
  | extend in_t = coalesce(column_ifexists("tcp.ask.input_tokens", real(0)), 0.0),
           out_t = coalesce(column_ifexists("tcp.ask.output_tokens", real(0)), 0.0),
           cr_t = coalesce(column_ifexists("tcp.ask.cache_read_tokens", real(0)), 0.0)
  | project timestamp, in_t, out_t, cr_t;
union from_traces, from_metrics
| summarize input_tokens=sum(in_t), output_tokens=sum(out_t), cache_read_tokens=sum(cr_t) by bin(timestamp, 1d)
| extend est_eur = (input_tokens*usd_per_token_input + output_tokens*usd_per_token_output + cache_read_tokens*usd_per_token_cache_read) * usd_to_eur
| project timestamp, input_tokens, output_tokens, cache_read_tokens, est_eur
| order by timestamp asc
